sys_script_include.script:
var IncentNowIngestionOrchestrator = Class.create();
IncentNowIngestionOrchestrator.prototype = {

    initialize: function() {},

    processRun: function(runSysId) {

        var result = {
            success: false,
            error_message: ""
        };

        try {

            /* =========================
               🔥 SANITIZE INPUT
            ========================= */

            if (!runSysId)
                throw "Run Sys ID not provided";

            var cleanId = (runSysId + "").trim(); // force string
            if (cleanId.length != 32)
                throw "Invalid Sys ID format: " + cleanId;

            /* =========================
               1️⃣ FETCH RUN RECORD
            ========================= */
            // safe to use runGR below
            var runGR = new GlideRecordSecure('x_ctans_incentnow_import_run');
            if (!runGR.get(cleanId)) {
                throw "Invalid Import Run: " + cleanId;
            }



            /* =========================
               2️⃣ VALIDATION
            ========================= */

            var validator = new IncentNowValidationEngine();
            var validationResult = validator.validateRun(cleanId);

            if (!validationResult || validationResult.valid == 0)
                throw "No valid rows to process";

            /* =========================
               3️⃣ DRY RUN CHECK
            ========================= */

            if (runGR.getValue("is_dry_run") == "true") {
                result.success = true;
                return result;
            }

            /* =========================
               4️⃣ TRANSFORM
            ========================= */

            var transformer = new IncentNowTransformEngine();
            transformer.execute(cleanId);

            result.success = true;

        } catch (ex) {

            result.success = false;
            result.error_message = ex.toString();
            gs.error("Ingestion Orchestrator Error: " + ex);
        }

        return result;
    },

    type: 'IncentNowIngestionOrchestrator'
};
